import styles from './App.module.scss';
import Header from "./components/Header";
import {BrowserRouter} from "react-router-dom";
import Routes from "./Routes";
import Modal from "./components/Modal";
import {Button} from "@mui/material";
import {useEffect, useState} from "react";

function App() {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [modalSetting, setModalSetting] = useState({
        title: '',
        actions: <></>
    });

    const [items, setItems] = useState([]);
    const [cartItems, setCartItems] = useState([]);

    useEffect(() => {
        const lSData = localStorage.getItem('data');

        if (lSData) {
            const parsedData = JSON.parse(lSData);
            setItems(parsedData?.items || []);
            setCartItems(parsedData?.cartItems || []);
            return;
        }

        (async () => {
            const { data } = await fetch('./items.json').then(res => res.json());
            setItems(data)
        })()
    }, [])

    const saveDataToLS = (items, cartItems) => {
        localStorage.setItem('data', JSON.stringify({
            items,
            cartItems,
        }))
    }

    const addToCart = (name, color) => {
        setCartItems(current => {
            const index = current.findIndex(({ name: itemName }) => itemName === name);

            if (index === -1) {
                const newState = [...current, {name, color, count: 1}]
                saveDataToLS(items, newState);
                return newState;
            }

            const newState = [ ...current ];
            newState[index].count = current[index].count + 1;
            saveDataToLS(items, newState);
            return newState;
        })
    }

    const deleteFromCart = (name) => {
        setCartItems(current => {
            const index = current.findIndex(({ name: itemName }) => itemName === name);

            const newState = [ ...current ];
            newState.splice(index,1);
            saveDataToLS(items, newState);
            return newState;
        })
    }

    const toggleFavorite = (id) => {
        setItems((current) => {
            const index = current.findIndex(({ id: itemId }) => id === itemId);

            if (index === -1) return current;

            const newState = [ ...current ];
            newState[index].isFavorite = !current[index].isFavorite;
            saveDataToLS(newState, cartItems);
            return newState;
        })
    }


    const openCartModal = (id, name, color) => {
        setModalSetting(({
            title: `Do you really want to add ${name} to the cart?`,
            actions: (
                <>
                    <Button onClick={() => {
                        addToCart(name, color);
                        setIsModalOpen(false);
                    }} variant='contained'>Yes</Button>
                    <Button variant='contained' color='warning' onClick={() => setIsModalOpen(false)}>No</Button>
                </>
            ),
        }));

        setIsModalOpen(true);
    };

    const openDeleteModal = (name) => {
        setModalSetting(({
            title: `Do you really want to delete ${name} from the cart?`,
            actions: (
                <>
                    <Button onClick={() => {
                        deleteFromCart(name);
                        setIsModalOpen(false);
                    }} variant='contained'>Yes</Button>
                    <Button variant='contained' color='warning' onClick={() => setIsModalOpen(false)}>No</Button>
                </>
            ),
        }));

        setIsModalOpen(true);
    };

  return (
      <BrowserRouter>
        <div className={styles.app}>
          <Header />
          <section>
            <Routes
                items={items}
                cartItems={cartItems}
                openCartModal={openCartModal}
                openDeleteModal={openDeleteModal}
                toggleFavorite={toggleFavorite}
            />
              <Modal
                  isOpen={isModalOpen}
                  setIsOpen={setIsModalOpen}
                  title={modalSetting.title}
                  actions={modalSetting.actions}
              />
          </section>
        </div>
      </BrowserRouter>
  );
}

export default App;
