import { Switch, Route } from "react-router-dom";
import HomePage from "./pages/HomePage";
import CartPage from "./pages/CartPage";
import FavouritePage from "./pages/FavouritePage";

const Routes = ({ items, openCartModal, cartItems, openDeleteModal, toggleFavorite }) => (
    <Switch>
        <Route exact path='/'>
            <HomePage items={items} openCartModal={openCartModal} toggleFavorite={toggleFavorite}/>
        </Route>

        <Route exact path='/cart'>
            <CartPage cartItems={cartItems} openDeleteModal={openDeleteModal}/>
        </Route>

        <Route exact path='/favourite'>
            <FavouritePage items={items} openCartModal={openCartModal} toggleFavorite={toggleFavorite}/>
        </Route>
    </Switch>
)

export default Routes;