import React, { useState, useEffect } from "react";
import Item from "../../components/Item";

const FavouritePage = ({ items, openCartModal, toggleFavorite }) => {
    const [favItems, setFavItems] = useState([])

    useEffect(() => {
        setFavItems(items.filter(({ isFavorite }) => isFavorite))
    }, [items])

    return (
        <>
            <h1>FAVOURITE</h1>
            <div style={{ display: 'flex', flexWrap: 'wrap' }}>
                {!favItems && <h2>No favorite  items yet.</h2>}
                {favItems && favItems.map(item => <Item key={item.id} {...item} openCartModal={openCartModal} toggleFavorite={toggleFavorite} />)}
            </div>
        </>
    )
}

export default FavouritePage;